import { useEffect, useState, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { generateReport, getReport } from '../lib/api';
import type { ReportData } from 'shared/types';
import { ReportCard } from '../components/ReportCard';
import { FileText, ArrowLeft, Printer, Loader2 } from 'lucide-react';

export function ReportPage() {
  const { sessionId } = useParams();
  const navigate = useNavigate();
  const [report, setReport] = useState<ReportData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function loadReport() {
      if (!sessionId) return;
      try {
        // Try getting existing first
        const existing = await getReport(sessionId).catch(() => null);
        if (existing) {
          setReport(existing);
          setIsLoading(false);
          return;
        }

        // Otherwise generate (takes time)
        const generated = await generateReport(sessionId);
        setReport(generated);
      } catch (err: any) {
        console.error('Failed to load report:', err);
        setError(err.message || 'Failed to generate report.');
      } finally {
        setIsLoading(false);
      }
    }
    loadReport();
  }, [sessionId]);

  const handlePrint = () => {
    window.print();
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center text-indigo-300 relative z-10 p-6">
        <Loader2 size={64} className="animate-spin mb-6" />
        <h2 className="text-2xl font-semibold mb-2">Analyzing Mutual Funds...</h2>
        <p className="text-slate-400 text-center max-w-md">
          Our AI is evaluating historical performance, volatility, and your profile to craft a personalized report. This may take up to a minute.
        </p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 relative z-10 text-center">
        <div className="bg-red-500/20 text-red-400 p-6 rounded-2xl max-w-md border border-red-500/50">
          <h2 className="text-xl font-bold mb-2">Error Generating Report</h2>
          <p>{error}</p>
          <button onClick={() => navigate('/')} className="btn-secondary mt-6">
            Return to Start
          </button>
        </div>
      </div>
    );
  }

  if (!report) return null;

  return (
    <div className="min-h-screen p-4 md:p-8 relative z-10 pb-24">
      <div className="max-w-5xl mx-auto">
        {/* Navigation Bar */}
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-8 print:hidden">
          <button 
            onClick={() => navigate('/')}
            className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors"
          >
            <ArrowLeft size={20} />
            Start New Session
          </button>
          
          <button 
            onClick={handlePrint}
            className="btn-secondary flex items-center gap-2"
          >
            <Printer size={18} />
            Print Report
          </button>
        </div>

        {/* Main Report */}
        <div className="animate-in fade-in slide-in-from-bottom-8 duration-700">
          <ReportCard report={report} />
        </div>
      </div>
    </div>
  );
}
